import { describe, it, expect, vi, beforeEach } from 'vitest';

vi.mock('../src/utils/spawn', () => ({
    spawnPM: vi.fn().mockResolvedValue({ exitCode: 0, stdout: '', stderr: '' }),
}));

vi.mock('../src/detect', () => ({
    detectPackageManager: vi.fn(),
}));

vi.mock('../src/utils/output', () => ({
    isJsonMode: vi.fn().mockReturnValue(false),
    printJSON: vi.fn(),
    printHuman: vi.fn(),
}));

import { exec } from '../src/commands/exec';
import { spawnPM } from '../src/utils/spawn';
import { detectPackageManager } from '../src/detect';

describe('exec', () => {
    beforeEach(() => { vi.clearAllMocks(); });

    it('should generate npx (npm exec) <pkg>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'npm', version: '10.0.0', reason: 'default' });
        await exec('vitest', [], {});
        expect(spawnPM).toHaveBeenCalledWith('npm', ['exec', '--', 'vitest'], expect.anything());
    });

    it('should generate yarn dlx <pkg>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'yarn', version: '4.0.0', reason: 'lockfile', lockfile: 'yarn.lock' });
        await exec('vitest', [], {});
        expect(spawnPM).toHaveBeenCalledWith('yarn', ['dlx', 'vitest'], expect.anything());
    });

    it('should generate pnpm dlx <pkg>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'pnpm', version: '8.0.0', reason: 'default' });
        await exec('vitest', [], {});
        expect(spawnPM).toHaveBeenCalledWith('pnpm', ['dlx', 'vitest'], expect.anything());
    });

    it('should generate bunx <pkg>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'bun', version: '1.0.0', reason: 'default' });
        await exec('vitest', [], {});
        expect(spawnPM).toHaveBeenCalledWith('bun', ['x', 'vitest'], expect.anything());
    });
});
